class Solution {
    public int maximumLength(String s) {
        int maxLen = -1;
        for (char c = 'a'; c <= 'z'; c++) {
            int count = 0;
            int currLen = 0;
            for (int i = 0; i < s.length(); i++) {
                if (s.charAt(i) == c) {
                    currLen++;
                } else {
                    if (currLen > 0) {
                        count++;
                        currLen = 0;
                    }
                }
            }
            if (currLen > 0) {
                count++;
            }
            if (count >= 3) {
                maxLen = Math.max(maxLen, currLen);
            }
        }
        return maxLen;
    }
}
```
